"use strict";exports.chunkMaterial=function(t,n=50){const e=t.trim();if(!e)return[];const i=e.split(/\n\n+/),s=[];let r="",l=0;for(const h of i){const t=h.trim();if(t)if(t.length>600){r.length>=n&&(s.push({index:l,text:r}),l+=1,r="");const e=t.split(new RegExp("(?<=[。！？!?；;\\n])"));let i="";for(const t of e)t&&(i.length+t.length>600&&i.length>=n?(s.push({index:l,text:i.trim()}),l+=1,i=t):i+=t);r=i.trim()}else r=r?`${r}\n\n${t}`:t}return r.trim().length>=n&&s.push({index:l,text:r.trim()}),0===s.length&&e.length>=n&&s.push({index:0,text:e}),s};
